   218	    public virtual async ValueTask TriggeredJobComplete(IOperableTrigger trigger, IJobDetail jobDetail, SchedulerInstruction triggerInstCode, CancellationToken cancellationToken = default)
   219	    {
   220	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
   221	        try
   222	        {
   223	            // It's possible that the job is null if:
   224	            //   1- it was deleted during execution
   225	            //   2- RAMJobStore is being used only for volatile jobs / triggers
   226	            //      from the JDBC job store
   227	
   228	            if (jobsByKey.TryGetValue(jobDetail.Key, out var jw))
   229	            {
   230	                IJobDetail jd = jw.JobDetail;
   231	
   232	                if (jobDetail.PersistJobDataAfterExecution)
   233	                {
   234	                    JobDataMap newData = jobDetail.JobDataMap;
   235	                    newData = (JobDataMap) newData.Clone();
   236	                    newData.ClearDirtyFlag();
   237	                    jd = jd.GetJobBuilder().SetJobData(newData).Build();
   238	                    jw.JobDetail = jd;
   239	                }
   240	
   241	                if (jd.ConcurrentExecutionDisallowed)
   242	                {
   243	                    blockedJobs.Remove(jd.Key);
   244	
   245	                    var triggerWrappersForJob = GetTriggerWrappersForJobNoLock(jd.Key);
   246	
   247	                    for (var i = 0; i < triggerWrappersForJob.Count; i++)
   248	                    {
   249	                        var ttw = triggerWrappersForJob[i];
   250	
   251	                        if (ttw.state == InternalTriggerState.Blocked)
   252	                        {
   253	                            ttw.state = InternalTriggerState.Waiting;
   254	                            timeTriggers.Add(ttw);
   255	                        }
   256	
   257	                        if (ttw.state == InternalTriggerState.PausedAndBlocked)
   258	                        {
   259	                            ttw.state = InternalTriggerState.Paused;
   260	                        }
   261	                    }
   262	
   263	                    await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
   264	                }
   265	            }
   266	            else
   267	            {
   268	                // even if it was deleted, there may be cleanup to do
   269	                blockedJobs.Remove(jobDetail.Key);
   270	            }
   271	
   272	            // check for trigger deleted during execution...
   273	            if (triggersByKey.TryGetValue(trigger.Key, out var tw))
   274	            {
   275	                if (triggerInstCode == SchedulerInstruction.DeleteTrigger)
   276	                {
   277	                    logger.LogDebug("Deleting trigger");
   278	                    DateTimeOffset? d = trigger.GetNextFireTimeUtc();
   279	                    if (!d.HasValue)
   280	                    {
   281	                        // double check for possible reschedule within job
   282	                        // execution, which would cancel the need to delete...
   283	                        d = tw.Trigger.GetNextFireTimeUtc();
   284	                        if (!d.HasValue)
   285	                        {
   286	                            await RemoveTriggerNoLock(trigger.Key, removeOrphanedJob: true, cancellationToken).ConfigureAwait(false);
   287	                        }
   288	                        else
   289	                        {
   290	                            logger.LogDebug("Deleting cancelled - trigger still active");
   291	                        }
   292	                    }
   293	                    else
   294	                    {
   295	                        await RemoveTriggerNoLock(trigger.Key, removeOrphanedJob: true, cancellationToken).ConfigureAwait(false);
   296	                        await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
   297	                    }
   298	                }
   299	                else if (triggerInstCode == SchedulerInstruction.SetTriggerComplete)
   300	                {
   301	                    tw.state = InternalTriggerState.Complete;
   302	                    timeTriggers.Remove(tw);
   303	                    await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
   304	                }
   305	                else if (triggerInstCode == SchedulerInstruction.SetTriggerError)
   306	                {
   307	                    logger.LogInformation("Trigger {TriggerKey} set to ERROR state.", trigger.Key);
   308	                    tw.state = InternalTriggerState.Error;
   309	                    await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
   310	                }
   311	                else if (triggerInstCode == SchedulerInstruction.SetAllJobTriggersError)
   312	                {
   313	                    logger.LogInformation("All triggers of Job {JobKey} set to ERROR state.", trigger.JobKey);
   314	                    SetAllTriggersOfJobToState(trigger.JobKey, InternalTriggerState.Error);
   315	                    await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
   316	                }
   317	                else if (triggerInstCode == SchedulerInstruction.SetAllJobTriggersComplete)
   318	                {
   319	                    SetAllTriggersOfJobToState(trigger.JobKey, InternalTriggerState.Complete);
   320	                    await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
   321	                }
   322	            }
   323	        }
