   399	                str.Append(tw.Trigger.Key.Name);
   400	                str.Append('/');
   401	            }
   402	
   403	            str.Append(" | ");
   404	
   405	            foreach (TriggerWrapper tw in timeTriggers)
   406	            {
   407	                str.Append(tw.Trigger.Key.Name);
   408	                str.Append("->");
   409	            }
   410	        }
   411	        finally
   412	        {
   413	            lockObject.Release();
   414	        }
   415	
   416	        return str.ToString();
