using System.Collections.Specialized;

using Quartz.Impl;
using Quartz.Listener;

namespace Quartz.Tests.Unit;

[NonParallelizable]
public class JobChainingRefireTest
{
    private IScheduler scheduler = null!;

    public class ChainedJob : IJob
    {
        public static int ExecutionCount;
        public static bool ShouldThrow;

        public ValueTask Execute(IJobExecutionContext context)
        {
            ExecutionCount++;
            if (ShouldThrow)
            {
                throw new JobExecutionException("test exception")
                {
                    RefireImmediately = true
                };
            }
            return default;
        }
    }

    public class NextJob : IJob
    {
        public static int ExecutionCount;

        public ValueTask Execute(IJobExecutionContext context)
        {
            ExecutionCount++;
            return default;
        }
    }

    [SetUp]
    public async Task SetUp()
    {
        ChainedJob.ExecutionCount = 0;
        ChainedJob.ShouldThrow = false;
        NextJob.ExecutionCount = 0;

        var properties = new NameValueCollection
        {
            ["quartz.serializer.type"] = TestConstants.DefaultSerializerType,
            ["quartz.scheduler.idleWaitTime"] = "1500"
        };
        ISchedulerFactory sf = new StdSchedulerFactory(properties);
        scheduler = await sf.GetScheduler();
    }

    [TearDown]
    public async Task TearDown()
    {
        if (scheduler is not null)
        {
            await scheduler.Shutdown(false);
        }
    }

    [Test]
